import{_ as r,o as l,c as o,a2 as a}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"🫘 黃豆追蹤日報 — 2026-05-13（週三）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-13.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-13.md"}'),i={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-13.md"};function n(e,t,s,d,g,h){return l(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="🫘-黃豆追蹤日報-—-2026-05-13-週三" tabindex="-1">🫘 黃豆追蹤日報 — 2026-05-13（週三） <a class="header-anchor" href="#🫘-黃豆追蹤日報-—-2026-05-13-週三" aria-label="Permalink to &quot;🫘 黃豆追蹤日報 — 2026-05-13（週三）&quot;">​</a></h1><blockquote><p>查詢時間：2026-05-13 05:00 TST（2026-05-12 21:00 UTC） 報告類型：每日追蹤 ⚠️ CBOT 期貨時段說明：05:00 TST 週三凌晨 = 17:00 ET 週二，黃豆期貨處於 14:00-20:00 ET 休息時段</p></blockquote><hr><h2 id="📊-即時報價" tabindex="-1">📊 即時報價 <a class="header-anchor" href="#📊-即時報價" aria-label="Permalink to &quot;📊 即時報價&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>報價</th><th>日漲跌</th><th>查詢時間</th><th>來源</th></tr></thead><tbody><tr><td>CBOT 黃豆 Jul 2026 (ZSN26)</td><td>1,220.00¢/蒲式耳</td><td>+7.00 (+0.58%)</td><td>2026-05-12</td><td>Yahoo Finance</td></tr><tr><td>CBOT 黃豆 May 2026 (ZSK26)</td><td>1,206.00¢</td><td>+6.25</td><td>2026-05-12</td><td>MarketWatch</td></tr><tr><td>CBOT 黃豆 Aug 2026</td><td>1,213.50¢</td><td>+5.50</td><td>2026-05-12</td><td>MarketWatch</td></tr><tr><td>CBOT 黃豆 Sep 2026</td><td>1,194.75¢</td><td>+4.50</td><td>2026-05-12</td><td>MarketWatch</td></tr><tr><td>WTI 原油</td><td>$102.18/桶</td><td>+4.19%</td><td>2026-05-12</td><td>CNBC</td></tr><tr><td>Brent 原油</td><td>~$104.51/桶</td><td>+0.29%</td><td>2026-05-12</td><td>IC Markets</td></tr><tr><td>BDI 波羅的海乾散貨</td><td>~2,977</td><td>連續 10 日下跌 -3.9%</td><td>2026-05-07</td><td>Facebook/BDI</td></tr><tr><td>Henry Hub 天然氣</td><td>~$2.92/MMBtu</td><td>+5.78%</td><td>2026-05-11</td><td>TradingEconomics</td></tr><tr><td>DCE 黃豆 7月</td><td>4,804 元/噸</td><td>—</td><td>2026-05-08</td><td>SunSirs</td></tr></tbody></table><blockquote><p><strong>查詢時間（TST）</strong>：2026-05-13 05:00</p></blockquote><hr><h2 id="🔍-敘事延續-usda-wasde-揭曉-26-27-年終庫存-310m-bu-—-低於預期" tabindex="-1">🔍 敘事延續：USDA WASDE 揭曉 26/27 年終庫存 310M bu — 低於預期 <a class="header-anchor" href="#🔍-敘事延續-usda-wasde-揭曉-26-27-年終庫存-310m-bu-—-低於預期" aria-label="Permalink to &quot;🔍 敘事延續：USDA WASDE 揭曉 26/27 年終庫存 310M bu — 低於預期&quot;">​</a></h2><p><strong>本日核心</strong>：5/12 USDA WASDE 月報公布首次 2026/27 作物年度官方預估，年終庫存 310M 蒲式耳，低於分析師預期（預期增加 15M），為黃豆價格提供支撐。同時，伊朗戰爭推升油價至 $102，通膨壓力上升。</p><hr><h2 id="_8-項追蹤指標" tabindex="-1">8 項追蹤指標 <a class="header-anchor" href="#_8-項追蹤指標" aria-label="Permalink to &quot;8 項追蹤指標&quot;">​</a></h2><h3 id="_1-usda-種植進度報告-每週" tabindex="-1">1. USDA 種植進度報告（每週） <a class="header-anchor" href="#_1-usda-種植進度報告-每週" aria-label="Permalink to &quot;1. USDA 種植進度報告（每週）&quot;">​</a></h3><ul><li><strong>最新數據</strong>：5/12 WASDE 公布 2026/27 年度預估</li><li><strong>2026/27 終庫存</strong>：310M 蒲式耳（低於 25/26 的 340M）</li><li><strong>2026/27 出口</strong>：1.63B 蒲式耳（+100M vs 25/26 的 1.53B）</li><li><strong>2026/27 壓榨</strong>：2.75B 蒲式耳（連續第 6 年創紀錄）</li><li><strong>2026/27 種植面積</strong>：待後續 WASDE 更新</li><li><strong>變化</strong>：🟢 <strong>重大變化</strong> — USDA 首次 26/27 年度預估低於預期，利多</li><li><strong>查詢時間</strong>：2026-05-12 12:00 ET</li><li>來源：Farm Progress (2026-05-12)、USDA WASDE (2026-05-12)</li></ul><h3 id="_2-巴西供應-收割-出口-豐收" tabindex="-1">2. 巴西供應（收割 + 出口 + 豐收） <a class="header-anchor" href="#_2-巴西供應-收割-出口-豐收" aria-label="Permalink to &quot;2. 巴西供應（收割 + 出口 + 豐收）&quot;">​</a></h3><ul><li><strong>巴西收割</strong>：2025/26 年度收割已基本完成</li><li><strong>巴西出口</strong>：持續強勁，中國需求轉向巴西</li><li><strong>USDA 2026/27 全球</strong>：全球年終庫存 1.957B 蒲式耳（-185M vs 25/26，但 +35M vs 預期）</li><li><strong>變化</strong>：🟡 無重大變化 — 巴西供應穩定，但全球庫存下降</li><li><strong>查詢時間</strong>：2026-05-12</li><li>來源：USDA WASDE (2026-05-12)</li></ul><h3 id="_3-尿素價格-多單訊號" tabindex="-1">3. 尿素價格 + 多單訊號 <a class="header-anchor" href="#_3-尿素價格-多單訊號" aria-label="Permalink to &quot;3. 尿素價格 + 多單訊號&quot;">​</a></h3><ul><li><strong>尿素</strong>：$547.50/噸（月 -21.9%）</li><li><strong>分析</strong>：尿素價格下跌 → 種植成本壓力減輕 → 但對黃豆價格影響有限</li><li><strong>變化</strong>：🟡 無重大變化 — 價格持續低位震盪</li><li><strong>查詢時間</strong>：2026-05-08</li><li>來源：TradingEconomics (2026-05-08)</li></ul><h3 id="_4-荷莫茲海峽通航狀態" tabindex="-1">4. 荷莫茲海峽通航狀態 <a class="header-anchor" href="#_4-荷莫茲海峽通航狀態" aria-label="Permalink to &quot;4. 荷莫茲海峽通航狀態&quot;">​</a></h3><ul><li><strong>狀態</strong>：⚠️ <strong>高度風險</strong> — 川普稱封鎖「100% effective」</li><li><strong>伊朗戰爭第 74 天</strong>：停火「on life support」，川普拒和</li><li><strong>Morgan Stanley 警告</strong>：若 Hormuz 完全關閉，Brent 可觸 $150/桶</li><li><strong>影響</strong>：油價 $102 → 運輸成本上升 → 黃豆出口成本增加</li><li><strong>變化</strong>：🔴 <strong>持續惡化</strong> — Hormuz 封鎖對糧食運輸構成威脅</li><li><strong>查詢時間</strong>：2026-05-12</li><li>來源：Bloomberg (2026-05-12)、Al Jazeera (2026-05-12)、Morgan Stanley (2026-05)</li></ul><h3 id="_5-中美貿易-中國進口" tabindex="-1">5. 中美貿易 + 中國進口 <a class="header-anchor" href="#_5-中美貿易-中國進口" aria-label="Permalink to &quot;5. 中美貿易 + 中國進口&quot;">​</a></h3><ul><li><strong>中國關稅</strong>：黃豆 13%（10% 全面附加稅 + 3% MFN 關稅）</li><li><strong>中國 4 月進口</strong>：+40%，含美國新採購</li><li><strong>川習會 5/14-15</strong>：預計討論農產品採購擴大</li><li><strong>USDA 2026/27 出口</strong>：1.63B 蒲式耳（+100M，反映貿易改善預期）</li><li><strong>變化</strong>：🟢 <strong>正面進展</strong> — 中國進口增加，川習會可能帶來進一步好消息</li><li><strong>查詢時間</strong>：2026-05-12</li><li>來源：Reuters/USNews (2026-05-12)、AgBull (2026-05-12)、USDA WASDE (2026-05-12)</li></ul><h3 id="_6-天然氣價格" tabindex="-1">6. 天然氣價格 <a class="header-anchor" href="#_6-天然氣價格" aria-label="Permalink to &quot;6. 天然氣價格&quot;">​</a></h3><ul><li><strong>Henry Hub</strong>：~$2.92/MMBtu（+5.78%）</li><li><strong>分析</strong>：天然氣價格穩定，對黃豆壓榨成本影響有限</li><li><strong>變化</strong>：🟡 無重大變化</li><li><strong>查詢時間</strong>：2026-05-11</li><li>來源：TradingEconomics (2026-05-11)</li></ul><h3 id="_7-聖嬰-拉尼娜氣候風險" tabindex="-1">7. 聖嬰/拉尼娜氣候風險 <a class="header-anchor" href="#_7-聖嬰-拉尼娜氣候風險" aria-label="Permalink to &quot;7. 聖嬰/拉尼娜氣候風險&quot;">​</a></h3><ul><li><strong>最新預測</strong>：60% 機率 2026 年下半年形成聖嬰，50% 機率為強聖嬰</li><li><strong>La Niña 已結束</strong>：IRI/SAWS/澳洲氣象局確認</li><li><strong>影響</strong>：聖嬰 → 亞洲/南美乾旱 → 黃豆/玉米減產風險</li><li><strong>時間框架</strong>：2026 Q3-Q4 形成，2027 年影響最大</li><li><strong>變化</strong>：🔴 <strong>重大變化</strong> — 聖嬰預期升溫，中期利多黃豆</li><li><strong>查詢時間</strong>：2026-05-12</li><li>來源：Reuters (2026-04-24)、Independent (2026-05)、IRI (2026-05)</li></ul><h3 id="_8-cbot-價格區間" tabindex="-1">8. CBOT 價格區間 <a class="header-anchor" href="#_8-cbot-價格區間" aria-label="Permalink to &quot;8. CBOT 價格區間&quot;">​</a></h3><ul><li><strong>Jul 2026</strong>：1,220.00¢（+0.58%）</li><li><strong>May 2026</strong>：1,206.00¢</li><li><strong>區間</strong>：1,194-1,220¢（近月合約）</li><li><strong>分析</strong>：觸及 2 年新高，USDA 庫存預估低於預期支撐</li><li><strong>查詢時間</strong>：2026-05-12</li><li>來源：Yahoo Finance (2026-05-12)、MarketWatch (2026-05-12)</li></ul><hr><h2 id="📰-即時新聞-5-條" tabindex="-1">📰 即時新聞（5 條） <a class="header-anchor" href="#📰-即時新聞-5-條" aria-label="Permalink to &quot;📰 即時新聞（5 條）&quot;">​</a></h2><ol><li><strong>USDA WASDE 5/12</strong>：2026/27 年終庫存 310M bu（低於預期），出口 1.63B bu（+100M），壓榨 2.75B bu（創紀錄）— <em>Farm Progress (2026-05-12)</em></li><li><strong>黃豆觸及 2 年新高</strong>：USDA 砍庫存 + 中國進口增加 — <em>Farm Progress (2026-05-12)</em></li><li><strong>川習會倒數</strong>：農產品採購 + 關稅減免談判 — <em>AgBull (2026-05-12)</em></li><li><strong>中國黃豆關稅 13%</strong>：10% 附加稅 + 3% MFN — <em>Reuters/USNews (2026-05-12)</em></li><li><strong>聖嬰預警</strong>：60% 機率 2026 下半年形成，可能為「超級聖嬰」— <em>Reuters (2026-04-24)</em></li></ol><hr><h2 id="🎯-情景分析" tabindex="-1">🎯 情景分析 <a class="header-anchor" href="#🎯-情景分析" aria-label="Permalink to &quot;🎯 情景分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>機率</th><th>價格影響</th><th>傳導機制</th></tr></thead><tbody><tr><td><strong>基準：川習會達成農產品協議 + 伊朗局勢穩定</strong></td><td>40%</td><td>Jul 1,200-1,250¢</td><td>貿易改善 → 出口預期升 → 庫存緊縮</td></tr><tr><td><strong>樂觀：伊朗停火 + 聖嬰預期升溫</strong></td><td>25%</td><td>Jul 1,250-1,350¢</td><td>運輸恢復 + 氣候風險 → 供給擔憂</td></tr><tr><td><strong>悲觀：伊朗升級 + Hormuz 封鎖</strong></td><td>35%</td><td>Jul 1,150-1,200¢</td><td>運輸中斷 → 出口受阻 → 價格承壓</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>Yahoo Finance (2026-05-12): Soybean Jul 2026 1,220.00¢</li><li>MarketWatch (2026-05-12): Soybeans continuous contract data</li><li>Farm Progress (2026-05-12): Soybeans hit 2-year high, USDA cuts stocks</li><li>USDA WASDE (2026-05-12): 2026/27 年度預估</li><li>CNBC (2026-05-12): WTI $102.18, S&amp;P 7,400.96</li><li>IC Markets (2026-05-12): Brent $104.51</li><li>TradingEconomics (2026-05-11): Henry Hub 天然氣</li><li>TradingEconomics (2026-05-08): 尿素 $547.50</li><li>SunSirs (2026-05-08): DCE 黃豆 4,804 元/噸</li><li>Reuters (2026-04-24): El Niño forecast 2026/27</li><li>Independent (2026-05): Super El Niño warning</li><li>Reuters/USNews (2026-05-12): 中國黃豆關稅 13%</li><li>AgBull (2026-05-12): 川習會農產品談判</li><li>Bloomberg (2026-05-12): 伊朗停火 + 油價</li><li>Al Jazeera (2026-05-12): Iran war Day 74</li><li>Morgan Stanley (2026-05): Hormuz 封鎖油價預測</li></ol>',36)])])}const b=r(i,[["render",n]]);export{c as __pageData,b as default};
